#include <bits/stdc++.h>
using namespace std;

#define int int64_t

using i32 = int32_t;
using i64 = int64_t;
using i128 = __int128_t;

using u32 = uint32_t;
using u64 =  uint64_t;
using u128 = __uint128_t;

#ifdef LOCAL
  #include "__DEBUG_TOOL.h"
#else 
  #define dbug(...)
#endif

// REGISTER_REFLECT()

void solve() {
  int n, c; cin >> n >> c;
  vector<int> a;
  for (int i = 1; i <= n; i ++) {
    int x; cin >> x;
    a.push_back(x - c);
  }

  sort(a.rbegin(), a.rend());
  int ans = 0, cnt = (n + 1) / 2;
  for (int i = 0; i < (n + 1) / 2; i ++) {
    ans += a[i];
  }
  
  for (int i = cnt; i < n; i ++) {
    if (a[i] > 0) {
      ans += a[i];
    }
  }

  cout << ans << '¥n';
} 

int32_t main() {
  std::ios::sync_with_stdio(false);
  std::cin.tie(nullptr);
  std::cout.tie(nullptr);
  
  int tt = 1, _ = 0;
  std::cin >> tt;
  while (tt-- and ++_)
    // std::cout << "TEST CASE : " << _ << endl,
    solve();

  return 0;
}

